from typing import List

def solve(weight: List[int]) -> int:
    max_count = 0
    start = 0

    for end in range(len(weight)):
        current_max = weight[start]
        for i in range(start, end + 1):
            if weight[i] > current_max:
                current_max = weight[i]

        if weight[end] < current_max:
            max_count += 1
            start = end + 1

    return max_count
```

```typescript
function solve(weight: number[]): number {
    let maxCount = 0;
    let start = 0;

    for (let end = 0; end < weight.length; end++) {
        // Keep track of the maximum weight in the current window
        let currentMax = weight[start];
        for (let i = start; i <= end; i++) {
            if (weight[i] > currentMax) {
                currentMax = weight[i];
            }
        }

        // Check if the current window is a balanced shipment
        if (weight[end] < currentMax) {
            maxCount++;
            start = end + 1; // Move start to the next position to avoid overlap
        }
    }

    return maxCount;
}
